The `trap` ensures cleanup even if the script fails.#!/bin/bash

# Define the temporary file path using the script's PID for uniqueness
TEMP_FILE="/tmp/myapp-$$.tmp"

# Ensure the temporary file is removed when the script exits,
# is interrupted (Ctrl+C), or encounters an error.
trap "rm -f \"$TEMP_FILE\"" EXIT INT TERM

echo "Script PID: $$"
echo "Temporary file path: $TEMP_FILE"

# --- Phase 1: Write initial data to the temporary file ---
echo "--- Writing initial data to $TEMP_FILE ---"
echo "First line of data" > "$TEMP_FILE"
echo "Second line of data" >> "$TEMP_FILE"
echo "Third line of data" >> "$TEMP_FILE"
echo "Another line here" >> "$TEMP_FILE"

echo "Content of $TEMP_FILE after initial write:"
cat "$TEMP_FILE"
echo ""

# --- Phase 2: Process the data and store results back into the same temporary file ---
# Example processing: Filter lines containing "line" and sort them.
# We use a temporary temporary file for safe in-place modification.
echo "--- Processing data (filtering and sorting) using $TEMP_FILE ---"
grep "line" "$TEMP_FILE" | sort > "${TEMP_FILE}.tmp"
mv "${TEMP_FILE}.tmp" "$TEMP_FILE"

echo "Content of $TEMP_FILE after processing 1:"
cat "$TEMP_FILE"
echo ""

# --- Phase 3: Further processing using the same temporary file ---
# Example processing: Convert all content to uppercase.
echo "--- Further processing (uppercasing) using $TEMP_FILE ---"
awk '{print toupper($0)}' "$TEMP_FILE" > "${TEMP_FILE}.tmp"
mv "${TEMP_FILE}.tmp" "$TEMP_FILE"

echo "Content of $TEMP_FILE after processing 2:"
cat "$TEMP_FILE"
echo ""

# --- Phase 4: Read the final results from the temporary file ---
echo "--- Reading final results from $TEMP_FILE ---"
FINAL_RESULTS=$(cat "$TEMP_FILE")
echo "Final processed data collected:"
echo "$FINAL_RESULTS"
echo ""

echo "Script finished. Temporary file $TEMP_FILE will be removed automatically."